// Hunt window and tuning knobs.
let StartTime = todatetime('{{StartTimeISO}}');
let EndTime = todatetime('{{EndTimeISO}}');
let BaselineWindow = 14d;
let PivotWindow = 60m;
// Optional allowlist for approved external automation sources.
let ApprovedPublicIps = dynamic([]);
// Stage A: successful Key Vault secret reads.
let KvReads =
  AzureActivity
  | where TimeGenerated between (StartTime .. EndTime)
  | extend Op = tolower(OperationNameValue),
           Status = tolower(tostring(ActivityStatusValue)),
           SubStatus = tolower(tostring(ActivitySubstatusValue)),
           CallerIp = tostring(CallerIpAddress),
           CallerNorm = tolower(tostring(Caller))
  // Keep only successful secret read actions from Key Vault provider paths.
  | where Op has "microsoft.keyvault/vaults/" and Op has "/secrets/" and Op has_any ("/get", "/read")
  | where Status in (dynamic(["success", "succeeded"])) or SubStatus has "ok"
  | where isnotempty(CallerIp)
  | summarize FirstKvRead=min(TimeGenerated), LastKvRead=max(TimeGenerated), KvReadCount=count(),
              KvOps=make_set(OperationNameValue, 15), KvResources=make_set(ResourceId, 25), KvCallers=make_set(CallerNorm, 15)
    by CallerIp;
// Baseline SPN sign-in tuples over prior 14 days.
let SpnBaseline =
  AADServicePrincipalSignInLogs
  | where TimeGenerated between ((StartTime - BaselineWindow) .. StartTime)
  | extend SpnId = tolower(tostring(ServicePrincipalId)),
           AppIdNorm = tolower(tostring(AppId)),
           IpNorm = tostring(IPAddress),
           UserAgentNorm = tostring(UserAgent),
           CredType = tolower(tostring(ClientCredentialType)),
           ResultNorm = tolower(tostring(ResultType))
  | where isnotempty(SpnId) and isnotempty(IpNorm)
  | where ResultNorm in (dynamic(["0", "success", "succeeded"]))
  | summarize by SpnId, AppIdNorm, IpNorm, UserAgentNorm, CredType;
// Current SPN sign-ins in hunt window.
let SpnCurrent =
  AADServicePrincipalSignInLogs
  | where TimeGenerated between (StartTime .. EndTime)
  | extend SpnId = tolower(tostring(ServicePrincipalId)),
           SpnName = tostring(ServicePrincipalName),
           AppIdNorm = tolower(tostring(AppId)),
           IpNorm = tostring(IPAddress),
           UserAgentNorm = tostring(UserAgent),
           CredType = tolower(tostring(ClientCredentialType)),
           ResultNorm = tolower(tostring(ResultType)),
           Asn = tostring(AutonomousSystemNumber)
  | where isnotempty(SpnId) and isnotempty(IpNorm)
  | where ResultNorm in (dynamic(["0", "success", "succeeded"]));
// Keep novel tuples only to highlight new SPN behavior.
let SpnNovel =
  SpnCurrent
  | join kind=leftanti SpnBaseline on SpnId, AppIdNorm, IpNorm, UserAgentNorm, CredType
  // Approximate non-1P network by public IP not present in local allowlist.
  | where not(ipv4_is_private(IpNorm))
  | where IpNorm !in (ApprovedPublicIps);
// Sequence correlation: Key Vault read from source IP before novel SPN sign-in.
KvReads
| join kind=inner SpnNovel on $left.CallerIp == $right.IpNorm
| where TimeGenerated between (FirstKvRead .. (LastKvRead + PivotWindow))
| summarize FirstKvRead=min(FirstKvRead), LastKvRead=max(LastKvRead), KvReadCount=max(KvReadCount),
            FirstSpnSignin=min(TimeGenerated), LastSpnSignin=max(TimeGenerated), SpnSigninCount=count(),
            KvOps=any(KvOps), KvResources=any(KvResources), KvCallers=any(KvCallers),
            UserAgents=make_set(UserAgentNorm, 10), CredentialTypes=make_set(CredType, 8),
            ASNs=make_set(Asn, 8), Resources=make_set(ResourceDisplayName, 15)
  by SourceIp=IpNorm, ServicePrincipalId=SpnId, ServicePrincipalName=SpnName, AppId=AppIdNorm
| extend TimeGenerated = FirstSpnSignin
| order by FirstSpnSignin desc

let StartTime = todatetime('{{StartTimeISO}}');
let EndTime = todatetime('{{EndTimeISO}}');
let SequenceWindow = 2h;
// Successful activity status values for AzureActivity write operations.
let SuccessActivityStatusValues = dynamic(["succeeded", "success"]);
// Exposure write operation families for Key Vault, Storage, and Azure database services.
let ExposureOpPrefixes = dynamic([
  "microsoft.keyvault/vaults/write",
  "microsoft.keyvault/vaults/accesspolicies/write",
  "microsoft.storage/storageaccounts/write",
  "microsoft.sql/servers/firewallrules/write",
  "microsoft.dbforpostgresql/",
  "microsoft.dbformysql/"
]);
// Parent operations that can carry network exposure changes in operation properties.
let ExposureParentWriteOps = dynamic([
  "microsoft.keyvault/vaults/write",
  "microsoft.storage/storageaccounts/write",
  "microsoft.sql/servers/write",
  "microsoft.dbforpostgresql/flexibleservers/write",
  "microsoft.dbformysql/flexibleservers/write"
]);
// Action fragments that indicate network posture or access control changes.
let ExposureActionValues = dynamic([
  "networkacls/write",
  "firewallrules/write",
  "virtualnetworkrules/write",
  "accesspolicies/write",
  "publicnetworkaccess/write"
]);
// Property tokens that indicate firewall, ACL, or public access weakening.
let NetworkConfigSignals = dynamic([
  "publicnetworkaccess",
  "networkacls",
  "defaultaction",
  "iprules",
  "virtualnetworkrules",
  "bypass",
  "firewallrules"
]);
// Service-specific access patterns used to detect post-exposure key or data access.
let KeyVaultAccessActions = dynamic(["/read", "/list", "secrets", "keys"]);
let StorageAccessActions = dynamic(["listkeys/action", "/list", "/read"]);
let SqlAccessActions = dynamic(["/read", "/list"]);
let PostgresAccessActions = dynamic(["/read", "/list", "listkeys"]);
let MysqlAccessActions = dynamic(["/read", "/list", "listkeys"]);
// Stage 1: Detect exposure-changing writes.
let ExposureWrites =
  AzureActivity
  | where TimeGenerated between (StartTime .. EndTime)
  | where isnotempty(Caller)
  | extend CallerNorm = tolower(Caller), CallerIp = tostring(CallerIpAddress), Op = tolower(OperationNameValue),
           ActivityStatusNorm = tolower(tostring(ActivityStatusValue)), Props = tolower(tostring(Properties_d))
  | where ActivityStatusNorm in (SuccessActivityStatusValues)
  | where Op has_any (ExposureOpPrefixes)
  | where (Op has_any (ExposureActionValues))
    or (Op in~ (ExposureParentWriteOps) and Props has_any (NetworkConfigSignals))
  | extend ServiceFamily = case(
      Op startswith "microsoft.keyvault/vaults/", "KeyVault",
      Op startswith "microsoft.storage/storageaccounts/", "Storage",
      Op startswith "microsoft.sql/servers/", "AzureSQL",
      Op startswith "microsoft.dbforpostgresql/", "PostgreSQL",
      Op startswith "microsoft.dbformysql/", "MySQL",
      "Other")
  | summarize FirstExposure=min(TimeGenerated), LastExposure=max(TimeGenerated), ExposureCount=count(),
              ExposureOps=make_set(OperationNameValue, 30), ExposureResources=make_set(ResourceId, 30),
              ServiceSet=make_set(ServiceFamily, 10)
    by CallerNorm, CallerIp, SubscriptionId;
// Stage 2: Detect key, secret, and data access operations after exposure tampering.
let AccessOps =
  AzureActivity
  | where TimeGenerated between (StartTime .. EndTime)
  | where isnotempty(Caller)
  | extend CallerNorm = tolower(Caller), CallerIp = tostring(CallerIpAddress), Op = tolower(OperationNameValue),
           ActivityStatusNorm = tolower(tostring(ActivityStatusValue))
  | where ActivityStatusNorm in (SuccessActivityStatusValues)
  | where (
      Op has "microsoft.keyvault/vaults/" and Op has_any (KeyVaultAccessActions)
    ) or (
      Op has "microsoft.storage/storageaccounts/" and Op has_any (StorageAccessActions)
    ) or (
      Op has "microsoft.sql/servers/databases/" and Op has_any (SqlAccessActions)
    ) or (
      Op has "microsoft.dbforpostgresql/" and Op has_any (PostgresAccessActions)
    ) or (
      Op has "microsoft.dbformysql/" and Op has_any (MysqlAccessActions)
    )
  | summarize FirstAccess=min(TimeGenerated), LastAccess=max(TimeGenerated), AccessCount=count(),
              AccessOps=make_set(OperationNameValue, 40), AccessResources=make_set(ResourceId, 40)
    by CallerNorm, CallerIp, SubscriptionId;
// Stage 3: Correlate multi-service exposure writes with follow-on access in a tight sequence window.
ExposureWrites
| extend DistinctServiceCount = array_length(ServiceSet)
| where DistinctServiceCount >= 2
| join kind=inner AccessOps on CallerNorm, SubscriptionId, CallerIp
| where FirstAccess between (FirstExposure .. (LastExposure + SequenceWindow))
| extend CallerName = iff(CallerNorm contains "@", tostring(split(CallerNorm, "@")[0]), CallerNorm),
         CallerUPNSuffix = iff(CallerNorm contains "@", tostring(split(CallerNorm, "@")[1]), "")
| project TimeGenerated=FirstExposure, Caller=CallerNorm, CallerIp, SubscriptionId,
          FirstExposure, LastExposure, FirstAccess, LastAccess,
          DistinctServiceCount, ExposureCount, AccessCount,
          CallerName, CallerUPNSuffix,
          ServiceSet, ExposureOps, AccessOps, ExposureResources, AccessResources
| order by DistinctServiceCount desc, ExposureCount desc, AccessCount desc, FirstAccess desc

let StartTime = todatetime('{{StartTimeISO}}');
let EndTime = todatetime('{{EndTimeISO}}');
let BaselineWindow = 14d;
let SequenceWindow = 4h;
// Successful activity status values for AzureActivity write operations.
let SuccessActivityStatusValues = dynamic(["succeeded", "success"]);
// Successful sign-in result values observed across interactive and non-interactive logs.
let SuccessResultValues = dynamic(["0", "success"]);
// Cloud providers in scope for network exposure tampering.
let ExposurePrefixes = dynamic([
  "microsoft.keyvault/vaults/",
  "microsoft.storage/storageaccounts/",
  "microsoft.sql/servers/",
  "microsoft.dbforpostgresql/",
  "microsoft.dbformysql/"
]);
// Action suffixes that indicate network protection weakening writes.
let ExposureActionValues = dynamic([
  "networkacls/write",
  "firewallrules/write",
  "accesspolicies/write",
  "virtualnetworkrules/write",
  "publicnetworkaccess/write"
]);
// Parent operations that can carry network exposure changes in operation properties.
let ExposureParentWriteOps = dynamic([
  "microsoft.keyvault/vaults/write",
  "microsoft.storage/storageaccounts/write",
  "microsoft.sql/servers/write",
  "microsoft.dbforpostgresql/flexibleservers/write",
  "microsoft.dbformysql/flexibleservers/write"
]);
// Property tokens that indicate firewall, ACL, or public access weakening.
let NetworkConfigSignals = dynamic([
  "publicnetworkaccess",
  "networkacls",
  "defaultaction",
  "iprules",
  "virtualnetworkrules",
  "bypass",
  "firewallrules"
]);
// Build a unified successful-signin stream for baseline and novelty analysis.
let SuccessfulSignins =
  union isfuzzy=true
    (SigninLogs
      | where TimeGenerated between ((StartTime - BaselineWindow) .. EndTime)
      | project TimeGenerated, Identity=tostring(coalesce(UserPrincipalName, Identity)), IPAddress=tostring(IPAddress),
                AppDisplayName=tostring(AppDisplayName), UserAgent=tostring(UserAgent), ResultType=tostring(ResultType)),
    (AADNonInteractiveUserSignInLogs
      | where TimeGenerated between ((StartTime - BaselineWindow) .. EndTime)
      | project TimeGenerated, Identity=tostring(coalesce(UserPrincipalName, Identity)), IPAddress=tostring(IPAddress),
                AppDisplayName=tostring(AppDisplayName), UserAgent=tostring(UserAgent), ResultType=tostring(ResultType))
  | extend ResultTypeNorm = tolower(ResultType)
  | where ResultTypeNorm in (SuccessResultValues)
  | where isnotempty(Identity) and isnotempty(IPAddress)
  | extend IdentityNorm = tolower(Identity), IpNorm = tolower(IPAddress), AppNorm = tolower(AppDisplayName), UaNorm = tolower(UserAgent);
// Baseline historical tuples to identify first-seen sign-in context in the hunt window.
let BaselineSignins =
  SuccessfulSignins
  | where TimeGenerated between ((StartTime - BaselineWindow) .. StartTime)
  | summarize by IdentityNorm, IpNorm, AppNorm, UaNorm;
// Keep only recent sign-ins that do not exist in baseline context.
let RecentNovelSignins =
  SuccessfulSignins
  | where TimeGenerated between (StartTime .. EndTime)
  | join kind=leftanti BaselineSignins on IdentityNorm, IpNorm, AppNorm, UaNorm
  | summarize FirstSignin=min(TimeGenerated), LastSignin=max(TimeGenerated), Apps=make_set(AppNorm, 10), UserAgents=make_set(UaNorm, 10)
    by IdentityNorm, IpNorm;
// Extract control-plane writes that can reduce network restrictions.
let ExposureWrites =
  AzureActivity
  | where TimeGenerated between (StartTime .. EndTime)
  | where isnotempty(Caller) and isnotempty(CallerIpAddress)
  | extend Op = tolower(OperationNameValue), CallerNorm = tolower(Caller), CallerIp = tolower(tostring(CallerIpAddress)),
           ActivityStatusNorm = tolower(tostring(ActivityStatusValue)), Props = tolower(tostring(Properties_d))
  | where ActivityStatusNorm in (SuccessActivityStatusValues)
  | where Op has_any (ExposurePrefixes)
  | where (Op has_any (ExposureActionValues))
    or (Op in~ (ExposureParentWriteOps) and Props has_any (NetworkConfigSignals))
  | extend ServiceFamily = case(
      Op startswith "microsoft.keyvault/vaults/", "KeyVault",
      Op startswith "microsoft.storage/storageaccounts/", "Storage",
      Op startswith "microsoft.sql/servers/", "AzureSQL",
      Op startswith "microsoft.dbforpostgresql/", "PostgreSQL",
      Op startswith "microsoft.dbformysql/", "MySQL",
      "Other")
  | summarize FirstWrite=min(TimeGenerated), LastWrite=max(TimeGenerated), ExposureCount=count(),
              ExposureOps=make_set(OperationNameValue, 30), ExposedResources=make_set(ResourceId, 30),
              ServiceSet=make_set(ServiceFamily, 10)
    by CallerNorm, CallerIp, SubscriptionId;
// Strong correlation path: same identity and source IP across sign-in and exposure write stages.
let StrongIdentityIpMatches =
  RecentNovelSignins
  | join kind=inner ExposureWrites on $left.IdentityNorm == $right.CallerNorm and $left.IpNorm == $right.CallerIp
  | where FirstWrite between (FirstSignin .. (LastSignin + SequenceWindow))
  | extend CorrelationStrength = "StrongIdentityAndIp";
// Fallback path for service and proxy edge-cases: retain IP-only correlation with reduced confidence.
let WeakIpOnlyMatches =
  RecentNovelSignins
  | join kind=inner ExposureWrites on $left.IpNorm == $right.CallerIp
  | where FirstWrite between (FirstSignin .. (LastSignin + SequenceWindow))
  | join kind=leftanti StrongIdentityIpMatches on IdentityNorm, IpNorm, CallerNorm, SubscriptionId, FirstWrite
  | extend CorrelationStrength = "WeakIpOnly";
union StrongIdentityIpMatches, WeakIpOnlyMatches
| extend DistinctServiceCount = array_length(ServiceSet),
         IdentityName = iff(IdentityNorm contains "@", tostring(split(IdentityNorm, "@")[0]), IdentityNorm),
         IdentityUPNSuffix = iff(IdentityNorm contains "@", tostring(split(IdentityNorm, "@")[1]), "")
| project TimeGenerated=FirstSignin, Identity=IdentityNorm, SigninIp=IpNorm, FirstSignin, LastSignin,
          Caller=CallerNorm, SubscriptionId, FirstWrite, LastWrite,
          DistinctServiceCount, ExposureCount,
          IdentityName, IdentityUPNSuffix,
          CorrelationStrength, Apps, UserAgents, ExposureOps, ExposedResources
| order by DistinctServiceCount desc, ExposureCount desc, FirstWrite desc

// Parameterized execution window supplied by the hunting framework.
let StartTime = todatetime('{{StartTimeISO}}');
let EndTime = todatetime('{{EndTimeISO}}');
let BaselineWindow = 14d;
let ReconWindow = 2h;
// Success filters for sign-ins and Azure control-plane operations.
let SuccessResultValues = dynamic(["0", "success"]);
let SuccessActivityStatusValues = dynamic(["succeeded", "success"]);
// IAM/resource discovery operations in scope.
let IamReconOps = dynamic([
  "microsoft.authorization/roleassignments/read",
  "microsoft.authorization/roledefinitions/read",
  "microsoft.resources/subscriptions/read",
  "microsoft.resources/subscriptions/resourcegroups/read",
  "microsoft.resources/subscriptions/resourcegroups/resources/read",
  "microsoft.resources/subscriptions/providers/read"
]);
// Build a unified successful sign-in stream from interactive and non-interactive logs.
let SuccessfulSignins =
  union isfuzzy=true
    (SigninLogs
    | where TimeGenerated between ((StartTime - BaselineWindow) .. EndTime)
    | project TimeGenerated, Identity=tostring(coalesce(UserPrincipalName, Identity)), IPAddress=tostring(IPAddress),
              AppDisplayName=tostring(AppDisplayName), UserAgent=tostring(UserAgent), ResultType=tostring(ResultType)),
    (AADNonInteractiveUserSignInLogs
    | where TimeGenerated between ((StartTime - BaselineWindow) .. EndTime)
    | project TimeGenerated, Identity=tostring(coalesce(UserPrincipalName, Identity)), IPAddress=tostring(IPAddress),
              AppDisplayName=tostring(AppDisplayName), UserAgent=tostring(UserAgent), ResultType=tostring(ResultType))
  | extend ResultTypeNorm = tolower(ResultType)
  | where ResultTypeNorm in (SuccessResultValues)
  | where isnotempty(Identity) and isnotempty(IPAddress)
  | extend IdentityNorm = tolower(Identity), IpNorm = tolower(IPAddress), AppNorm = tolower(AppDisplayName), UaNorm = tolower(UserAgent);
// Baseline historical sign-in tuples for novelty detection.
let BaselineSignins =
  SuccessfulSignins
  | where TimeGenerated between ((StartTime - BaselineWindow) .. StartTime)
  | summarize by IdentityNorm, IpNorm, AppNorm, UaNorm;
// Keep only first-seen tuples during the hunt window.
let NovelSignins =
  SuccessfulSignins
  | where TimeGenerated between (StartTime .. EndTime)
  | join kind=leftanti BaselineSignins on IdentityNorm, IpNorm, AppNorm, UaNorm
  | summarize FirstSignin=min(TimeGenerated), LastSignin=max(TimeGenerated),
              Apps=make_set(AppNorm, 10), UserAgents=make_set(UaNorm, 10)
    by IdentityNorm, IpNorm;
// Aggregate successful IAM reconnaissance by caller and source IP.
let IamRecon =
  AzureActivity
  | where TimeGenerated between (StartTime .. EndTime)
  | where isnotempty(Caller) and isnotempty(CallerIpAddress)
  | extend CallerNorm = tolower(Caller), CallerIp = tolower(tostring(CallerIpAddress)), Op = tolower(OperationNameValue),
           StatusNorm = tolower(tostring(ActivityStatusValue)), SubStatusNorm = tolower(tostring(ActivitySubstatusValue))
  | where Op in (IamReconOps)
  | where StatusNorm in (SuccessActivityStatusValues) or SubStatusNorm has "ok"
  // Dedupe multi-stage AzureActivity records for a single logical operation.
  | extend ActionKey = iff(
      isnotempty(CorrelationId),
      strcat(CorrelationId, "|", Op, "|", CallerNorm),
      strcat(CallerNorm, "|", CallerIp, "|", Op, "|", tostring(SubscriptionId), "|", tostring(ResourceId), "|", tostring(bin(TimeGenerated, 1m)))
    )
  | summarize arg_min(TimeGenerated, *) by ActionKey
  | summarize ReconCount=count(), DistinctReconOps=dcount(Op),
              ReconOps=make_set(OperationNameValue, 20),
              ReconCorrelationIds=make_set_if(CorrelationId, isnotempty(CorrelationId), 30),
              FirstRecon=min(TimeGenerated), LastRecon=max(TimeGenerated),
              Subscriptions=dcount(SubscriptionId), ResourceGroups=dcountif(ResourceGroup, isnotempty(ResourceGroup))
    by CallerNorm, CallerIp;
// Sequence novel sign-in context into near-term IAM reconnaissance.
NovelSignins
| join kind=inner IamRecon on $left.IdentityNorm == $right.CallerNorm and $left.IpNorm == $right.CallerIp
| where FirstRecon between (FirstSignin .. (LastSignin + ReconWindow))
| where ReconCount >= 8 and DistinctReconOps >= 3 and Subscriptions >= 1
| extend IdentityName = iff(IdentityNorm contains "@", tostring(split(IdentityNorm, "@")[0]), IdentityNorm),
         IdentityUPNSuffix = iff(IdentityNorm contains "@", tostring(split(IdentityNorm, "@")[1]), "")
| project TimeGenerated=FirstSignin, Identity=IdentityNorm, SigninIp=IpNorm,
          IdentityName, IdentityUPNSuffix,
          FirstSignin, LastSignin, FirstRecon, LastRecon,
          ReconCount, DistinctReconOps, Subscriptions, ResourceGroups,
          Apps, UserAgents, ReconOps, ReconCorrelationIds
| order by ReconCount desc, FirstRecon desc

let StartTime = todatetime('{{StartTimeISO}}');
let EndTime = todatetime('{{EndTimeISO}}');
// Parent processes commonly associated with web or app services.
let ServiceParents = dynamic([
  "w3wp.exe", "httpd.exe", "nginx.exe", "apache2", "tomcat9.exe", "tomcat",
  "java.exe", "java", "node.exe", "dotnet.exe", "php-cgi.exe", "php.exe"
]);
// Child processes and utilities often used after code execution.
let SuspiciousChildren = dynamic([
  "cmd.exe", "powershell.exe", "pwsh.exe", "sh", "bash", "curl", "wget",
  "certutil.exe", "bitsadmin.exe", "mshta.exe", "rundll32.exe", "python.exe", "python3"
]);
// Command-line tokens that suggest staging, download, or shell execution.
let StagingTokens = dynamic(["http://", "https://", " -enc ", " /c ", " /bin/sh", "wget ", "curl "]);
// Suspicious execution chain: service parent spawning risky child process/command.
let SuspiciousExec =
  _Im_ProcessEvent(starttime=StartTime, endtime=EndTime)
  | where EventType =~ "ProcessCreated"
  | extend ParentProcess = tolower(coalesce(ActingProcessFilename, ActingProcessFileOriginalName)),
           ChildProcess = tolower(coalesce(TargetProcessFilename, TargetProcessFileOriginalName)),
           ChildCommandLine = coalesce(TargetProcessCommandLine, "")
  | where ParentProcess in~ (ServiceParents)
  | where ChildProcess in~ (SuspiciousChildren) or ChildCommandLine has_any (StagingTokens)
  | project ExecTime = TimeGenerated,
            DeviceId = tostring(coalesce(DvcId, DvcHostname)),
            DeviceName = coalesce(DvcHostname, DvcFQDN),
            FileName = ChildProcess,
            ProcessCommandLine = ChildCommandLine,
            InitiatingProcessFileName = ParentProcess,
            InitiatingProcessCommandLine = tostring(ActingProcessCommandLine);
// Access to Azure IMDS endpoint, commonly used to request managed identity tokens.
let ImdsAccess =
  _Im_NetworkSession(starttime=StartTime, endtime=EndTime)
  | where DstIpAddr == "169.254.169.254"
  | where EventResult !~ "Failure"
  | project DeviceId = tostring(coalesce(DvcId, DvcHostname)),
            ImdsTime = TimeGenerated,
            ImdsRemotePort = DstPortNumber,
            ImdsRemoteUrl = tostring(EventReportUrl);
// Optional confidence booster: near-term outbound public egress from same host.
let PublicEgress =
  _Im_NetworkSession(starttime=StartTime, endtime=EndTime)
  | where isnotempty(DstIpAddr)
  | where not(
      ipv4_is_in_range(DstIpAddr, "10.0.0.0/8")
      or ipv4_is_in_range(DstIpAddr, "172.16.0.0/12")
      or ipv4_is_in_range(DstIpAddr, "192.168.0.0/16")
      or ipv4_is_in_range(DstIpAddr, "127.0.0.0/8")
      or ipv4_is_in_range(DstIpAddr, "169.254.0.0/16")
    )
  | where EventResult !~ "Failure"
  | project DeviceId = tostring(coalesce(DvcId, DvcHostname)),
            EgressTime = TimeGenerated,
            RemoteIP = DstIpAddr,
            RemotePort = DstPortNumber,
            RemoteUrl = tostring(EventReportUrl);
// Correlate suspicious process execution to IMDS access in a short time window.
SuspiciousExec
| join kind=innerunique ImdsAccess on DeviceId
| where ImdsTime between (ExecTime .. (ExecTime + 10m))
// Attach optional public egress shortly after execution.
| join kind=leftouter PublicEgress on DeviceId
| where isempty(EgressTime) or EgressTime between (ExecTime .. (ExecTime + 15m))
// Escalate confidence if both IMDS and public egress are observed.
| extend Confidence = iff(isempty(EgressTime), "High", "VeryHigh")
| extend TimeGenerated = ExecTime
| project TimeGenerated, Confidence, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine,
          FileName, ProcessCommandLine, ImdsTime, ImdsRemotePort, ImdsRemoteUrl, EgressTime, RemoteIP, RemotePort, RemoteUrl
| order by TimeGenerated desc

let StartTime = todatetime('{{StartTimeISO}}');
let EndTime = todatetime('{{EndTimeISO}}');
// Parent processes commonly associated with web-facing services.
let WebServiceParents = dynamic([
  "w3wp.exe", "httpd.exe", "nginx.exe", "apache2", "tomcat9.exe",
  "java.exe", "java", "node.exe", "dotnet.exe", "php-cgi.exe", "php.exe"
]);
// Child processes and utilities frequently seen in post-exploitation chains.
let RareChildProcesses = dynamic([
  "cmd.exe", "powershell.exe", "pwsh.exe", "sh", "bash", "curl", "wget",
  "certutil.exe", "bitsadmin.exe", "mshta.exe", "rundll32.exe", "python.exe", "python3"
]);
// Command-line indicators that suggest staging, download, or shell launch behavior.
let EgressIndicators = dynamic(["http://", "https://", "-enc", "/c ", "/bin/sh", "wget ", "curl "]);
// Find suspicious child process executions launched by web-service parents.
let RareChildren =
  _Im_ProcessEvent(starttime=StartTime, endtime=EndTime)
  | where EventType =~ "ProcessCreated"
  | extend ParentProcess = tolower(coalesce(ActingProcessFilename, ActingProcessFileOriginalName)),
           ChildProcess = tolower(coalesce(TargetProcessFilename, TargetProcessFileOriginalName)),
           ChildCommandLine = coalesce(TargetProcessCommandLine, "")
  | where ParentProcess in~ (WebServiceParents)
  | where ChildProcess in~ (RareChildProcesses)
    or ChildCommandLine has_any (EgressIndicators)
  | project ProcessTime = TimeGenerated,
            DeviceId = tostring(coalesce(DvcId, DvcHostname)),
            DeviceName = coalesce(DvcHostname, DvcFQDN),
            InitiatingProcessFileName = ParentProcess,
            InitiatingProcessCommandLine = tostring(ActingProcessCommandLine),
            FileName = ChildProcess,
            ProcessCommandLine = ChildCommandLine;
// Capture successful outbound connections to public (non-private) IP space.
let OutboundConnections =
  _Im_NetworkSession(starttime=StartTime, endtime=EndTime)
  | where isnotempty(DstIpAddr)
  | where not(
      ipv4_is_in_range(DstIpAddr, "10.0.0.0/8")
      or ipv4_is_in_range(DstIpAddr, "172.16.0.0/12")
      or ipv4_is_in_range(DstIpAddr, "192.168.0.0/16")
      or ipv4_is_in_range(DstIpAddr, "100.64.0.0/10")
      or ipv4_is_in_range(DstIpAddr, "127.0.0.0/8")
      or ipv4_is_in_range(DstIpAddr, "169.254.0.0/16")
      or ipv6_is_in_range(DstIpAddr, "::1/128")
      or ipv6_is_in_range(DstIpAddr, "fc00::/7")
      or ipv6_is_in_range(DstIpAddr, "fe80::/10")
    )
  | where EventResult !~ "Failure"
  | project DeviceId = tostring(coalesce(DvcId, DvcHostname)),
            RemoteIP = DstIpAddr,
            RemotePort = DstPortNumber,
            NetworkTime = TimeGenerated;
// Correlate suspicious child execution with near-term public egress on the same host.
RareChildren
| join kind=innerunique OutboundConnections on DeviceId
| where NetworkTime between (ProcessTime .. (ProcessTime + 5m))
| extend TimeGenerated = ProcessTime
| project TimeGenerated, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine,
          FileName, ProcessCommandLine, RemoteIP, RemotePort
| order by TimeGenerated desc

let StartTime = todatetime('{{StartTimeISO}}');
let EndTime = todatetime('{{EndTimeISO}}');
let BaselineStart = StartTime - 14d;
let BaselineEnd = EndTime + 1d;
// Parent and child process families used to model remote admin execution chains.
let RemoteParents = dynamic(["wmiprvse.exe", "wsmprovhost.exe", "psexesvc.exe", "winrs.exe"]);
let SuspiciousChildren = dynamic(["cmd.exe", "powershell.exe", "pwsh.exe", "net.exe", "net1.exe", "whoami.exe", "nltest.exe", "reg.exe", "certutil.exe", "rundll32.exe", "mshta.exe"]);
// Build latest hybrid identity keys for robust joins.
let HybridUsersRaw =
  IdentityInfo
  | extend Timestamp = column_ifexists('Timestamp', TimeGenerated)
  | extend AccountUpn = coalesce(column_ifexists('AccountUpn', ''), column_ifexists('AccountUPN', ''))
  | where Timestamp between (BaselineStart .. BaselineEnd)
  | where column_ifexists('IdentityEnvironment', '') =~ "Hybrid" or (isnotempty(column_ifexists('AccountSID', '')) and isnotempty(AccountObjectId))
  | project Timestamp, AccountObjectId, AccountUpn, AccountDomain, AccountName, BlastRadius
  | summarize arg_max(Timestamp, *) by AccountObjectId
  | extend UPNKey = tolower(AccountUpn),
           SamKey = tolower(strcat(AccountDomain, "\\", AccountName));
// Normalize key variants into one joinable user key.
let HybridUsers =
  union isfuzzy=true
    (HybridUsersRaw | where isnotempty(UPNKey) | project UserKey = UPNKey, HybridUPN = AccountUpn, HybridSam = strcat(AccountDomain, "\\", AccountName), BlastRadius),
    (HybridUsersRaw | where isnotempty(SamKey) | project UserKey = SamKey, HybridUPN = AccountUpn, HybridSam = strcat(AccountDomain, "\\", AccountName), BlastRadius);
// Keep latest hybrid or Entra-joined endpoint inventory.
let HybridDevicesRaw =
  DeviceInfo
  | where TimeGenerated between (BaselineStart .. BaselineEnd)
  | project TimeGenerated, DeviceId, DeviceName, JoinType, IsAzureADJoined
  | summarize arg_max(TimeGenerated, *) by DeviceId
  | where IsAzureADJoined == true or tostring(JoinType) has_any ("Hybrid", "Azure AD", "Entra")
  | project DeviceId, HybridDeviceName = DeviceName, JoinType;
let HybridDevices =
  union isfuzzy=true
    (HybridDevicesRaw | where isnotempty(DeviceId) | project DeviceJoinKey = tolower(DeviceId), HybridDeviceName, JoinType),
    (HybridDevicesRaw | where isnotempty(HybridDeviceName) | project DeviceJoinKey = tolower(HybridDeviceName), HybridDeviceName, JoinType);
// Identify suspicious remote execution patterns on endpoints.
let RemoteExec =
  _Im_ProcessEvent(starttime=StartTime, endtime=EndTime)
  | where EventType =~ "ProcessCreated"
  | extend ParentProcess = tolower(coalesce(ActingProcessFilename, ActingProcessFileOriginalName)),
           ParentOriginal = tolower(ActingProcessFileOriginalName),
           ChildProcess = tolower(coalesce(TargetProcessFilename, TargetProcessFileOriginalName)),
           ChildCommandLine = tostring(TargetProcessCommandLine),
           UserKey = tolower(coalesce(ActorUsername, TargetUsername)),
           DeviceJoinKey = tolower(coalesce(DvcId, DvcHostname)),
           SourceIP = tostring(DvcIpAddr)
  | where ParentProcess in~ (RemoteParents) or ParentOriginal in~ (RemoteParents)
  | where ChildProcess in~ (SuspiciousChildren)
      or ChildCommandLine has_any (" -enc ", "sekurlsa", "lsass", " /node:", " -computername ", "invoke-command", "win32_process", "create ")
  | where isnotempty(UserKey)
  | where isnotempty(DeviceJoinKey)
  | project ExecTime = TimeGenerated, DeviceJoinKey, UserKey, SourceIP,
            ParentProcess, ChildProcess, ChildCommandLine;
// Gather successful cloud sign-ins for same identities.
let CloudUserSignins =
  _Im_Authentication(starttime=StartTime, endtime=(EndTime + 1d))
  | where EventResult in~ ("Success", "Partial")
  | where EventProduct =~ "Microsoft Entra ID"
  | where LogonProtocol has_any ("OAuth", "OpenID", "SAML")
    or LogonMethod in~ ("Service Principal", "Managed Identity", "Username & Password", "Multi factor authentication", "Passwordless", "PKI")
  | extend UserKey = tolower(coalesce(ActorUsername, TargetUsername)),
           CloudIP = tostring(SrcIpAddr),
           AppName = tostring(TargetAppName)
  | where isnotempty(UserKey)
  | project SigninTime = TimeGenerated, UserKey, CloudIP, AppName, CorrelationId = EventOriginalUid;
// Correlate remote exec to near-term cloud access by same hybrid identity.
RemoteExec
| join kind=inner HybridDevices on DeviceJoinKey
| join kind=innerunique HybridUsers on UserKey
| join kind=inner CloudUserSignins on UserKey
| where SigninTime between (ExecTime .. (ExecTime + 2h))
| summarize FirstCloudSignin = min(SigninTime),
            LastCloudSignin = max(SigninTime),
            CloudSigninCount = count(),
            Apps = make_set(AppName, 10),
            CloudIPs = make_set(CloudIP, 10),
            CorrelationIds = make_set(CorrelationId, 10)
  by ExecTime, HybridDeviceName, JoinType, SourceIP, ParentProcess,
    ChildProcess, ChildCommandLine, HybridUPN, HybridSam,
    BlastRadius
  | extend Confidence = iff(BlastRadius =~ "high", "High", "Medium")
| extend TimeGenerated = ExecTime
| order by TimeGenerated desc
